const express = require('express');
const app = express();
const sendgrid = require('@sendgrid/mail');
const twilio = require('twilio');

// Set up SendGrid and Twilio API keys
sendgrid.setApiKey(process.env.SENDGRID_API_KEY);
twilio.accountSid = process.env.TWILIO_ACCOUNT_SID;
twilio.authToken = process.env.TWILIO_AUTH_TOKEN;

// Set up Express routes for email and SMS
app.post('/email', (req, res) => {
  const { to, subject, text } = req.body;
  sendgrid.send({
    to,
    subject,
    text,
  });
});

app.post('/sms', (req, res) => {
  const { to, body } = req.body;
  twilio.messages.create({
    to,
    from: '+1234567890', // Replace with your Twilio phone number
    body,
  });
});

// Start the server
const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Server started on port ${port}`);
});